import os
import glob

# Check what files are available in the working directory
print("Current directory:", os.getcwd())
print("Files in current directory:")
for item in sorted(os.listdir('.')):
    if os.path.isfile(item):
        print(f"  {item} ({os.path.getsize(item)} bytes)")

# Check outputs directory
if os.path.exists('outputs'):
    print("\nFiles in outputs/ directory:")
    for item in sorted(os.listdir('outputs'))[:50]:
        if os.path.isfile(f'outputs/{item}'):
            print(f"  {item} ({os.path.getsize(f'outputs/{item}') / 1024:.1f} KB)")
        elif os.path.isdir(f'outputs/{item}'):
            print(f"  {item}/ (directory)")
    if len(os.listdir('outputs')) > 50:
        print(f"  ... and {len(os.listdir('outputs')) - 50} more items")
else:
    print("\nNo outputs/ directory")

# Look for JSON files with query_db in the name
json_files = glob.glob('*.json') + glob.glob('outputs/*.json')
print(f"\nFound {len(json_files)} JSON files:")
for f in sorted(json_files):
    size = os.path.getsize(f) / 1024 / 1024  # MB
    print(f"  {f} ({size:.2f} MB)")

